import React, { useState, useEffect } from 'react';
import Sidebar from './components/Sidebar';
import Player from './components/Player';
import Home from './pages/Home';
import Search from './pages/Search';
import MoodRecommend from './pages/MoodRecommend';
import Library from './pages/Library';
import './App.css';

export default function App() {
  const [currentPage, setCurrentPage] = useState('home');
  const [currentTrack, setCurrentTrack] = useState(null);
  const [queue, setQueue] = useState([]);
  const [isPlaying, setIsPlaying] = useState(false);
  const [likedTracks, setLikedTracks] = useState([]);
  const [recentTracks, setRecentTracks] = useState([]);

  const playTrack = (track, trackList = []) => {
    setCurrentTrack(track);
    setIsPlaying(true);
    setQueue(trackList.length > 0 ? trackList : [track]);
    setRecentTracks(prev => {
      const filtered = prev.filter(t => t.id !== track.id);
      return [track, ...filtered].slice(0, 20);
    });
  };

  const toggleLike = (track) => {
    setLikedTracks(prev => {
      const exists = prev.find(t => t.id === track.id);
      return exists ? prev.filter(t => t.id !== track.id) : [...prev, track];
    });
  };

  const isLiked = (trackId) => likedTracks.some(t => t.id === trackId);

  const playNext = () => {
    if (!currentTrack || queue.length === 0) return;
    const idx = queue.findIndex(t => t.id === currentTrack.id);
    if (idx < queue.length - 1) playTrack(queue[idx + 1], queue);
  };

  const playPrev = () => {
    if (!currentTrack || queue.length === 0) return;
    const idx = queue.findIndex(t => t.id === currentTrack.id);
    if (idx > 0) playTrack(queue[idx - 1], queue);
  };

  const pages = { home: Home, search: Search, mood: MoodRecommend, library: Library };
  const PageComponent = pages[currentPage] || Home;

  return (
    <div className="app">
      <Sidebar currentPage={currentPage} setCurrentPage={setCurrentPage} />
      <main className="main-content">
        <PageComponent
          playTrack={playTrack}
          toggleLike={toggleLike}
          isLiked={isLiked}
          currentTrack={currentTrack}
          isPlaying={isPlaying}
          likedTracks={likedTracks}
          recentTracks={recentTracks}
        />
      </main>
      <Player
        currentTrack={currentTrack}
        isPlaying={isPlaying}
        setIsPlaying={setIsPlaying}
        onNext={playNext}
        onPrev={playPrev}
        toggleLike={toggleLike}
        isLiked={isLiked}
      />
    </div>
  );
}
